describe('ReportingserviceForm — create', () => {
  const onSuccess = jest.fn();

  beforeEach(() => onSuccess.mockClear());

  it('renders all required fields', () => {
    render(<ReportingserviceForm onSuccess={onSuccess} />);


    expect(screen.getByLabelText(/name/i)).toBeInTheDocument();





    expect(screen.getByLabelText(/title/i)).toBeInTheDocument();



    expect(screen.getByLabelText(/document type/i)).toBeInTheDocument();



    expect(screen.getByLabelText(/effective date/i)).toBeInTheDocument();



    expect(screen.getByLabelText(/expiry date/i)).toBeInTheDocument();



    expect(screen.getByLabelText(/status/i)).toBeInTheDocument();






  });

  it('shows validation errors on empty submit', async () => {
    render(<ReportingserviceForm onSuccess={onSuccess} />);
    await userEvent.click(screen.getByRole('button', { name: /save|create|submit/i }));
    await waitFor(() => {
      const alerts = screen.queryAllByRole('alert');
      expect(alerts.length).toBeGreaterThan(0);
    });
    expect(onSuccess).not.toHaveBeenCalled();
  });

  it('submits successfully with valid data and calls onSuccess', async () => {
    render(<ReportingserviceForm onSuccess={onSuccess} />);


    await userEvent.type(screen.getByLabelText(/name/i), 'valid-name');





    await userEvent.type(screen.getByLabelText(/title/i), 'valid-title');



    await userEvent.type(screen.getByLabelText(/document type/i), 'valid-document_type');












    await userEvent.click(screen.getByRole('button', { name: /save|create|submit/i }));
    await waitFor(() => expect(onSuccess).toHaveBeenCalledTimes(1));
  });

  it('shows server error when API returns 422', async () => {
    server.use(
      rest.post(`${BASE}/api/v1/reporting-services`, (_req, res, ctx) =>
        res(ctx.status(422), ctx.json({ detail: [{ loc: ['body', 'name'], msg: 'field required' }] }))
      )
    );
    render(<ReportingserviceForm onSuccess={onSuccess} />);


    await userEvent.type(screen.getByLabelText(/name/i), 'x');





    await userEvent.type(screen.getByLabelText(/title/i), 'x');



    await userEvent.type(screen.getByLabelText(/document type/i), 'x');












    await userEvent.click(screen.getByRole('button', { name: /save|create|submit/i }));
    await waitFor(() => expect(screen.getByRole('alert')).toBeInTheDocument());
  });
});

